import { Component, h, Prop } from '@stencil/core';
import { RenderCardContent } from '../../utils/card-content-renderer';
import { HeadingLevel } from '../../models/card.model';

@Component({
  tag: 'wdpr-card-micro-content',
  shadow: true,
  styles: `:host { display: flex; align-items: center; width: 100%; }`
})
export class WdprCardMicroContent {
  @Prop() primaryHeadline: string;
  @Prop() body: string;
  @Prop() disabled: boolean = false;
  @Prop({ attribute: 'heading-level' }) headingLevel: HeadingLevel = 'h3';

  render() {
    const props = {
      body: this.body,
      primaryHeadline: this.primaryHeadline,
      headingLevel: this.headingLevel,
    };

    return (
      <RenderCardContent disabled={this.disabled} variant='micro' {...props} />
    );
  }
}